solution_code:
#include <iostream>

class A
{
public:
    int m_value{};
    A(int value) : m_value{value} {}
};

class B : virtual public A
{
public:
    B(int value) : A{value} {}
    void addViaB(int n) { m_value += n; }
};

class C : virtual public A
{
public:
    C(int value) : A{value} {}
    void addViaC(int n) { m_value += n; }
};

class D : public B, public C
{
public:
    D(int start) : A{start}, B{start}, C{start} {}
    int getCount() const { return m_value; }
};

int main()
{
    int start{}, b{}, c{};
    std::cin >> start >> b >> c;

    D d{start};
    d.addViaB(b);
    std::cout << "via B: " << d.getCount() << '\n';
    d.addViaC(c);
    std::cout << "via C: " << d.getCount() << '\n';
    std::cout << "shared: " << d.getCount() << '\n';
    return 0;
}

