solution_code:
#include <iostream>

class A
{
public:
    int m_id{};
    A(int id) : m_id{id} {}
};

class B : virtual public A
{
public:
    int m_observed{};
    // When a B is built as part of a D, the shared virtual A has ALREADY been
    // constructed by D (with dId), so m_id here is dId, not aId. The A{aId}
    // below is ignored in that case.
    B(int aId, int tag) : A{aId}, m_observed{m_id + tag} {}
};

class C : virtual public A
{
public:
    int m_observed{};
    C(int aId, int tag) : A{aId}, m_observed{m_id + tag} {}
};

class D : public B, public C
{
public:
    D(int bId, int cId, int dId, int bTag, int cTag)
        : A{dId}, B{bId, bTag}, C{cId, cTag} {}
    void show() const
    {
        std::cout << "A id: " << m_id << '\n';
        std::cout << "B observed: " << B::m_observed << '\n';
        std::cout << "C observed: " << C::m_observed << '\n';
    }
};

int main()
{
    int bId{}, cId{}, dId{}, bTag{}, cTag{};
    std::cin >> bId >> cId >> dId >> bTag >> cTag;

    D d{bId, cId, dId, bTag, cTag};
    d.show();
    return 0;
}
